#include <bits/stdc++.h>
#define int long long
using namespace std;
using namespace std;
int n, m, r;
int father[100005];
int dep[100005];
int siz[100005];
int son[100005];
int top[100005];
int ide[100005];
int rid[100005];
int cnt;
int val[100005], p;
vector <int> e[100005];
struct Tree {
	int Left, Right;
	int value, sum;
};
Tree tr[500005];
void dfs1 (int u, int fa) {
	father[u] = fa;
	dep[u] = dep[fa] + 1;
	siz[u] = 1;
	for (auto v : e[u]) {
		if (v == fa) {
			continue;
		}
		dfs1 (v, u);
		siz[u] += siz[v];
		if (siz[v] > siz[son[u]]) {
			son[u] = v;
		}
	}
	return;
}
void dfs2 (int u, int fir) {
	cnt++;
	top[u] = fir;
	ide[u] = cnt;
	rid[ide[u]] = u;
	if (!son[u]) {
		return;
	}
	dfs2 (son[u], fir);
	for (auto v : e[u]) {
		if (v != father[u] && v != son[u]) {
			dfs2 (v, v);
		}
	}
    return ;
}
void push_up (int id) {
	tr[id].value = tr[id << 1].value + tr[id << 1 | 1].value;
}
void build (int id, int Left, int Right) {
	tr[id].Left = Left;
	tr[id].Right = Right;
	if (Left == Right) {
		tr[id].value = val[rid[Left]];
		return ;
	}
	int mid = (Left + Right) / 2;
	build (id << 1, Left, mid);
	build (id << 1 | 1, mid + 1, Right);
	push_up (id);
	return ;
}
void push_down (int id) {
	tr[id << 1].sum += tr[id].sum;
	tr[id << 1 | 1].sum += tr[id].sum;
	tr[id << 1].value += tr[id].sum * (tr[id << 1].Right - tr[id << 1].Left + 1);
	tr[id << 1 | 1].value += tr[id].sum * (tr[id << 1 | 1].Right - tr[id << 1 | 1].Left + 1);
	tr[id].sum = 0;
	return ;
}
void update (int id, int Left, int Right, int value) {
	if (tr[id].Left >= Left && tr[id].Right <= Right) {
		tr[id].sum += value;
		tr[id].value += value * (tr[id].Right - tr[id].Left + 1);
		return;
	}
	push_down (id);
	int mid = (tr[id].Left + tr[id].Right) >> 1;
	if (Right <= mid) {
		update (id << 1, Left, Right, value);
	} else if (Left > mid) {
		update (id << 1 | 1, Left, Right, value);
	} else {
		update (id << 1, Left, mid, value);
		update (id << 1 | 1, mid + 1, Right, value);
	}
	push_up (id);
    return ;
}
long long query (int id, int Left, int Right) {
	if (tr[id].Left >= Left && tr[id].Right <= Right) {
		return tr[id].value;
	} else {
		int mid = (tr[id].Left + tr[id].Right) / 2;
		push_down (id);
		if (Right <= mid) {
			return query (id << 1, Left, Right);
		}
		if (Left > mid) {
			return query (id << 1 | 1, Left, Right);
		} else {
			return query (id << 1, Left, mid) + query (id << 1 | 1, mid + 1, Right);
		}
	}
}
void treechange (int id, int value) {
	int x = ide[id];
	int y = ide[id] + siz[id] - 1;
	update (1, x, y, value);
	return ;
}
int treequery (int id) {
	int x = ide[id];
	int y = ide[id] + siz[id] - 1;
	return query (1, x, y);
}
void linkchange (int x, int y, int value) {
	int tx = top[x];
	int ty = top[y];
	while (tx != ty) {
		if (dep[tx] < dep[ty]) {
			swap (x, y);
			swap (tx, ty);
		}
		update (1, ide[tx], ide[x], value);
		x = father[tx];
		tx = top[x];
	}
	if (dep[x] > dep[y]) {
		swap (x, y);
	}
	update (1, ide[x], ide[y], value);
	return ;
}
int linkquery (int x, int y) {
	int tx = top[x];
	int ty = top[y];
	int ans = 0;
	while (tx != ty) {
		if (dep[tx] < dep[ty]) {
			swap (x, y);
			swap (tx, ty);
		}
		ans += query (1, ide[tx], ide[x]);
		x = father[tx];
		tx = top[x];
	}
	if (dep[x] > dep[y]) {
		swap (x, y);
	}
	ans += query (1, ide[x], ide[y]);
	return ans;
}
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n;
	for (int i = 1; i < n; i++) {
		int u, v;
		cin >> u >> v;
		e[u + 1].push_back (v + 1);
		e[v + 1].push_back (u + 1);
	}
	dfs1 (1, 0);
	dfs2 (1, 1);
	build (1, 1, cnt); 
	cin >> m;
	for (int i = 1; i <= m; i++) {
		int u, v, d;
		char c;
		cin >> c;
		if (c == 'A') {
			cin >> u >> v >> d;
			linkchange (u + 1, v + 1, d);
		} else {
			cin >> u;
			cout << treequery (u + 1) << '\n';
		}
	}
	return 0;
}
